SAMPLE_RATE = 44100

def generate_tone(freq, duration_ms, volume=0.5, wave_type='sine', fade=True):
    """Generate a tone as a pygame Sound object."""
    n_samples = int(SAMPLE_RATE * duration_ms / 1000)
    t = np.linspace(0, duration_ms / 1000, n_samples, endpoint=False)
    if wave_type == 'sine':
        wave = np.sin(2 * np.pi * freq * t)
    elif wave_type == 'square':
        wave = np.sign(np.sin(2 * np.pi * freq * t))
    elif wave_type == 'sawtooth':
        wave = 2 * (t * freq - np.floor(t * freq + 0.5))
    elif wave_type == 'noise':
        wave = np.random.uniform(-1, 1, n_samples)
    else:
        wave = np.sin(2 * np.pi * freq * t)

    if fade and n_samples > 100:
        fade_len = min(int(n_samples * 0.1), 2000)
        wave[:fade_len] *= np.linspace(0, 1, fade_len)
        wave[-fade_len:] *= np.linspace(1, 0, fade_len)

    wave = (wave * volume * 32767).astype(np.int16)
    stereo = np.column_stack([wave, wave])
    return pygame.sndarray.make_sound(stereo)

def generate_explosion_sound():
    """Generate an explosion sound."""
    n_samples = int(SAMPLE_RATE * 1.5)
    noise = np.random.uniform(-1, 1, n_samples)
    # Exponential decay envelope
    envelope = np.exp(-np.linspace(0, 8, n_samples))
    # Low-pass-ish: mix with low freq sine
    t = np.linspace(0, 1.5, n_samples)
    low = np.sin(2 * np.pi * 60 * t) * 0.5
    wave = (noise * envelope + low * envelope) * 0.7
    wave = np.clip(wave, -1, 1)
    wave = (wave * 32767).astype(np.int16)
    stereo = np.column_stack([wave, wave])
    return pygame.sndarray.make_sound(stereo)

def generate_success_sound():
    """Generate a success jingle."""
    notes = [523, 659, 784, 1047]  # C5, E5, G5, C6
    segments = []
    for freq in notes:
        n = int(SAMPLE_RATE * 0.15)
        t = np.linspace(0, 0.15, n, endpoint=False)
        wave = np.sin(2 * np.pi * freq * t)
        fade_len = int(n * 0.1)
        wave[:fade_len] *= np.linspace(0, 1, fade_len)
        wave[-fade_len:] *= np.linspace(1, 0, fade_len)
        segments.append(wave)
    full = np.concatenate(segments)
    full = (full * 0.6 * 32767).astype(np.int16)
    stereo = np.column_stack([full, full])
    return pygame.sndarray.make_sound(stereo)

def generate_thrust_chunk():
    """Generate a short thrust sound chunk for looping."""
    n_samples = int(SAMPLE_RATE * 0.1)
    noise = np.random.uniform(-1, 1, n_samples)
    t = np.linspace(0, 0.1, n_samples)
    rumble = np.sin(2 * np.pi * 80 * t) * 0.4
    wave = (noise * 0.3 + rumble) * 0.5
    wave = (wave * 32767).astype(np.int16)
    stereo = np.column_stack([wave, wave])
    return pygame.sndarray.make_sound(stereo)

def generate_warning_sound():
    """Generate a warning beep."""
    n_samples = int(SAMPLE_RATE * 0.3)
    t = np.linspace(0, 0.3, n_samples)
    wave = np.sin(2 * np.pi * 880 * t)
    fade_len = int(n_samples * 0.05)
    wave[:fade_len] *= np.linspace(0, 1, fade_len)
    wave[-fade_len:] *= np.linspace(1, 0, fade_len)
    wave = (wave * 0.5 * 32767).astype(np.int16)
    stereo = np.column_stack([wave, wave])
    return pygame.sndarray.make_sound(stereo)

