def generate_terrain(width, height, num_landing_pads=2):
    """Generate random lunar terrain with flat landing pads."""
    points = []
    pad_positions = []

    # Generate rough terrain using midpoint displacement
    num_segments = 20
    segment_width = width // num_segments
    base_height = height * 0.65

    # Start with base heights
    heights = []
    for i in range(num_segments + 1):
        variation = random.uniform(-80, 80)
        h = base_height + variation
        h = max(height * 0.4, min(height * 0.85, h))
        heights.append(h)

    # Choose landing pad positions
    pad_indices = random.sample(range(2, num_segments - 2), num_landing_pads)
    pad_width_segments = 3  # segments wide

    for pad_idx in pad_indices:
        pad_h = heights[pad_idx]
        for j in range(pad_width_segments):
            if pad_idx + j <= num_segments:
                heights[pad_idx + j] = pad_h
        pad_x_start = pad_idx * segment_width
        pad_x_end = (pad_idx + pad_width_segments) * segment_width
        pad_positions.append({
            'x': pad_x_start,
            'width': pad_x_end - pad_x_start,
            'y': pad_h,
            'center_x': (pad_x_start + pad_x_end) // 2
        })

    # Build polygon points
    for i in range(num_segments + 1):
        points.append((i * segment_width, int(heights[i])))

    # Close the polygon at the bottom
    terrain_polygon = points + [(width, height), (0, height)]

    return terrain_polygon, points, pad_positions

