# Particle system
# ─────────────────────────────────────────────
class Particle:
    def __init__(self, x, y, vx, vy, color, lifetime, size=2):
        self.x = x
        self.y = y
        self.vx = vx
        self.vy = vy
        self.color = color
        self.lifetime = lifetime
        self.max_lifetime = lifetime
        self.size = size

    def update(self):
        self.x += self.vx
        self.y += self.vy
        self.vy += 0.05  # gravity on particles
        self.lifetime -= 1
        return self.lifetime > 0

    def draw(self, surface):
        alpha = self.lifetime / self.max_lifetime
        r = int(self.color[0] * alpha)
        g = int(self.color[1] * alpha)
        b = int(self.color[2] * alpha)
        size = max(1, int(self.size * alpha))
        pygame.draw.circle(surface, (r, g, b), (int(self.x), int(self.y)), size)

# ─────────────────────────────────────────────
# Lander class
# ─────────────────────────────────────────────
class Lander:
    def __init__(self, x, y):
        self.x = float(x)
        self.y = float(y)
        self.vx = random.uniform(-1.0, 1.0)
        self.vy = 0.0
        self.angle = 0.0  # degrees, 0 = upright
        self.fuel = 100.0
        self.thrusting = False
        self.rotating_left = False
        self.rotating_right = False
        self.alive = True
        self.landed = False
        self.particles = []
        self.width = 30
        self.height = 40
        self.thrust_sound_playing = False

    def get_vertices(self):
        """Get lander vertices rotated by current angle."""
        angle_rad = math.radians(self.angle)
        cos_a = math.cos(angle_rad)
        sin_a = math.sin(angle_rad)

        # Lander shape: body + legs
        local_pts = [
            (0, -20),    # top
            (12, -5),    # top-right
            (15, 10),    # right
            (10, 15),    # bottom-right body
            (-10, 15),   # bottom-left body
            (-15, 10),   # left
            (-12, -5),   # top-left
        ]

        rotated = []
        for lx, ly in local_pts:
            rx = lx * cos_a - ly * sin_a + self.x
            ry = lx * sin_a + ly * cos_a + self.y
            rotated.append((rx, ry))
        return rotated

    def get_leg_points(self):
        """Get landing leg endpoints."""
        angle_rad = math.radians(self.angle)
        cos_a = math.cos(angle_rad)
        sin_a = math.sin(angle_rad)

        legs = [
            # (start_local, end_local)
            ((10, 15), (20, 28)),   # right leg
            ((-10, 15), (-20, 28)), # left leg
        ]

        result = []
        for (lx1, ly1), (lx2, ly2) in legs:
            rx1 = lx1 * cos_a - ly1 * sin_a + self.x
            ry1 = lx1 * sin_a + ly1 * cos_a + self.y
            rx2 = lx2 * cos_a - ly2 * sin_a + self.x
            ry2 = lx2 * sin_a + ly2 * cos_a + self.y
            result.append(((rx1, ry1), (rx2, ry2)))
        return result

    def get_bottom_center(self):
        """Get the bottom center of the lander (for collision)."""
        angle_rad = math.radians(self.angle)
        cos_a = math.cos(angle_rad)
        sin_a = math.sin(angle_rad)
        lx, ly = 0, 28  # bottom of legs
        rx = lx * cos_a - ly * sin_a + self.x
        ry = lx * sin_a + ly * cos_a + self.y
        return rx, ry

    def get_foot_points(self):
        """Get the two foot points for landing detection."""
        angle_rad = math.radians(self.angle)
        cos_a = math.cos(angle_rad)
        sin_a = math.sin(angle_rad)
        feet_local = [(20, 28), (-20, 28)]
        feet = []
        for lx, ly in feet_local:
            rx = lx * cos_a - ly * sin_a + self.x
            ry = lx * sin_a + ly * cos_a + self.y
            feet.append((rx, ry))
        return feet

    def get_thrust_point(self):
        """Get the thrust exhaust point."""
        angle_rad = math.radians(self.angle)
        cos_a = math.cos(angle_rad)
        sin_a = math.sin(angle_rad)
        lx, ly = 0, 20
        rx = lx * cos_a - ly * sin_a + self.x
        ry = lx * sin_a + ly * cos_a + self.y
        return rx, ry

    def update(self, keys):
        if not self.alive or self.landed:
            # Update existing particles
            self.particles = [p for p in self.particles if p.update()]
            return

        # Rotation
        self.rotating_left = keys[pygame.K_LEFT] or keys[pygame.K_a]
        self.rotating_right = keys[pygame.K_RIGHT] or keys[pygame.K_d]

        if self.rotating_left:
            self.angle -= ROTATION_SPEED
        if self.rotating_right:
            self.angle += ROTATION_SPEED

        # Thrust
        self.thrusting = (keys[pygame.K_UP] or keys[pygame.K_w] or keys[pygame.K_SPACE]) and self.fuel > 0

        if self.thrusting:
            angle_rad = math.radians(self.angle)
            self.vx += -math.sin(angle_rad) * THRUST_POWER
            self.vy += -math.cos(angle_rad) * THRUST_POWER
            self.fuel = max(0, self.fuel - FUEL_CONSUMPTION)

            # Thrust particles
            tx, ty = self.get_thrust_point()
            for _ in range(3):
                spread = random.uniform(-0.5, 0.5)
                angle_rad2 = math.radians(self.angle)
                pvx = math.sin(angle_rad2) * random.uniform(1, 4) + spread + self.vx * 0.3
                pvy = math.cos(angle_rad2) * random.uniform(1, 4) + spread + self.vy * 0.3
                color = random.choice([ORANGE, YELLOW, WHITE, RED])
                self.particles.append(Particle(tx, ty, pvx, pvy, color, random.randint(10, 25), size=random.randint(2, 4)))

        # Gravity
        self.vy += GRAVITY

        # Move
        self.x += self.vx
        self.y += self.vy

        # Wrap horizontally
        if self.x < -20:
            self.x = WIDTH + 20
        elif self.x > WIDTH + 20:
            self.x = -20

        # Update particles
        self.particles = [p for p in self.particles if p.update()]

    def draw(self, surface):
        # Draw particles
        for p in self.particles:
            p.draw(surface)

        if not self.alive:
            return

        # Draw legs
        legs = self.get_leg_points()
        for (start, end) in legs:
            pygame.draw.line(surface, GRAY, (int(start[0]), int(start[1])), (int(end[0]), int(end[1])), 2)

        # Draw body
        verts = self.get_vertices()
        int_verts = [(int(v[0]), int(v[1])) for v in verts]
        pygame.draw.polygon(surface, LIGHT_BLUE, int_verts)
        pygame.draw.polygon(surface, WHITE, int_verts, 2)

        # Draw window
        angle_rad = math.radians(self.angle)
        cos_a = math.cos(angle_rad)
        sin_a = math.sin(angle_rad)
        wx = -0 * cos_a - (-8) * sin_a + self.x
        wy = -0 * sin_a + (-8) * cos_a + self.y
        pygame.draw.circle(surface, CYAN, (int(wx), int(wy)), 6)
        pygame.draw.circle(surface, WHITE, (int(wx), int(wy)), 6, 1)

        # Draw thrust flame
        if self.thrusting:
            tx, ty = self.get_thrust_point()
            flame_len = random.uniform(15, 30)
            fx = tx + math.sin(angle_rad) * flame_len
            fy = ty + math.cos(angle_rad) * flame_len
            # Flame triangle
            perp_x = math.cos(angle_rad) * 5
            perp_y = -math.sin(angle_rad) * 5
            flame_pts = [
                (int(tx - perp_x), int(ty - perp_y)),
                (int(tx + perp_x), int(ty + perp_y)),
                (int(fx), int(fy))
            ]
            pygame.draw.polygon(surface, ORANGE, flame_pts)
            pygame.draw.polygon(surface, YELLOW, [
                (int(tx - perp_x * 0.5), int(ty - perp_y * 0.5)),
                (int(tx + perp_x * 0.5), int(ty + perp_y * 0.5)),
                (int(fx * 0.7 + tx * 0.3), int(fy * 0.7 + ty * 0.3))
            ])

# ─────────────────────────────────────────────
# Collision detection
# ─────────────────────────────────────────────
def get_terrain_y_at_x(terrain_points, x):
    """Get terrain height at a given x coordinate."""
    for i in range(len(terrain_points) - 1):
        x1, y1 = terrain_points[i]
        x2, y2 = terrain_points[i + 1]
        if x1 <= x <= x2:
            if x2 == x1:
                return y1
            t = (x - x1) / (x2 - x1)
            return y1 + t * (y2 - y1)
    return HEIGHT

def check_landing(lander, terrain_points, pad_positions):
    """Check if lander has landed or crashed."""
    feet = lander.get_foot_points()
    speed = math.sqrt(lander.vx ** 2 + lander.vy ** 2)
    angle = abs(lander.angle % 360)
    if angle > 180:
        angle = 360 - angle

    for fx, fy in feet:
        terrain_y = get_terrain_y_at_x(terrain_points, fx)
        if fy >= terrain_y:
            # Check if on a landing pad
            on_pad = False
            for pad in pad_positions:
                if pad['x'] <= fx <= pad['x'] + pad['width']:
                    on_pad = True
                    break

            if on_pad and speed <= MAX_SAFE_LANDING_SPEED and angle <= MAX_SAFE_LANDING_ANGLE:
                return 'landed'
            else:
                return 'crashed'
    return None

