def draw_hud(surface, lander, score, level):
    speed = math.sqrt(lander.vx ** 2 + lander.vy ** 2)
    angle = abs(lander.angle % 360)
    if angle > 180:
        angle = 360 - angle

    # Background panel
    panel = pygame.Surface((220, 130), pygame.SRCALPHA)
    panel.fill((0, 0, 0, 160))
    surface.blit(panel, (10, 10))

    # Fuel bar
    fuel_color = GREEN if lander.fuel > 30 else (YELLOW if lander.fuel > 10 else RED)
    pygame.draw.rect(surface, DARK_GRAY, (20, 20, 100, 14))
    pygame.draw.rect(surface, fuel_color, (20, 20, int(lander.fuel), 14))
    pygame.draw.rect(surface, WHITE, (20, 20, 100, 14), 1)
    fuel_text = font_small.render(f"FUEL: {int(lander.fuel)}%", True, WHITE)
    surface.blit(fuel_text, (130, 18))

    # Speed
    speed_color = GREEN if speed < MAX_SAFE_LANDING_SPEED else (YELLOW if speed < MAX_SAFE_LANDING_SPEED * 2 else RED)
    speed_text = font_small.render(f"SPEED: {speed:.2f}", True, speed_color)
    surface.blit(speed_text, (20, 42))

    # Angle
    angle_color = GREEN if angle < MAX_SAFE_LANDING_ANGLE else (YELLOW if angle < MAX_SAFE_LANDING_ANGLE * 2 else RED)
    angle_text = font_small.render(f"ANGLE: {angle:.1f}°", True, angle_color)
    surface.blit(angle_text, (20, 62))

    # Altitude
    terrain_y = get_terrain_y_at_x(terrain_points_global, lander.x)
    altitude = max(0, terrain_y - lander.y)
    alt_text = font_small.render(f"ALT: {int(altitude)}m", True, WHITE)
    surface.blit(alt_text, (20, 82))

    # Score & Level
    score_text = font_small.render(f"SCORE: {score}  LVL: {level}", True, YELLOW)
    surface.blit(score_text, (20, 102))

    # Controls hint
    ctrl_text = font_small.render("↑/W: Thrust  ←→/AD: Rotate", True, GRAY)
    surface.blit(ctrl_text, (WIDTH // 2 - 130, HEIGHT - 25))

def draw_landing_pads(surface, pad_positions):
    for pad in pad_positions:
        # Pad surface
        pygame.draw.rect(surface, GRAY,
                         (int(pad['x']), int(pad['y']) - 3, int(pad['width']), 6))
        # Pad markings
        center_x = int(pad['center_x'])
        pad_y = int(pad['y'])
        pygame.draw.line(surface, YELLOW, (center_x - 15, pad_y - 3), (center_x + 15, pad_y - 3), 2)
        # Lights
        for lx in [pad['x'] + 5, pad['x'] + pad['width'] - 5]:
            color = GREEN if pygame.time.get_ticks() % 1000 < 500 else DARK_GRAY
            pygame.draw.circle(surface, color, (int(lx), pad_y - 5), 4)

