def draw_result_screen(surface, state, score, level):
    overlay = pygame.Surface((WIDTH, HEIGHT), pygame.SRCALPHA)
    overlay.fill((0, 0, 0, 180))
    surface.blit(overlay, (0, 0))

    if state == STATE_LANDED:
        msg = "✓ SUCCESSFUL LANDING!"
        color = GREEN
        sub = f"+{score} points"
    elif state == STATE_CRASHED:
        msg = "✗ CRASH LANDING!"
        color = RED
        sub = "No points awarded"
    else:
        msg = "GAME OVER"
        color = YELLOW
        sub = f"Final Score: {score}"

    title = font_large.render(msg, True, color)
    surface.blit(title, (WIDTH // 2 - title.get_width() // 2, HEIGHT // 2 - 60))

    sub_txt = font_medium.render(sub, True, WHITE)
    surface.blit(sub_txt, (WIDTH // 2 - sub_txt.get_width() // 2, HEIGHT // 2))

    cont_txt = font_small.render("Press ENTER for next level  |  ESC for menu", True, GRAY)
    surface.blit(cont_txt, (WIDTH // 2 - cont_txt.get_width() // 2, HEIGHT // 2 + 60))

